/**
 * @type {number[]}
 */
const myArr = [21, 54, 87, 98, 'hello']; // -> Keine Prüfung

myArr.push('world'); // Warnmeldung

/**
 * @type {{name: string, age: number, isActive: boolean}} 
 */
const user = {
    name: 'Max Mustermann',
    age: true,
    isActive: true,
};

user.name = 123;  // -> deutliche Warnmeldung

/**
 * @type {{name: string, age?: number, isActive: boolean}}
 */
const user = {
    name: 'Max Mustermann',
    isActive: true,
};
